import { DatePipe } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormControl, FormGroup } from "@angular/forms";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";

@Component({
  selector: "app-client-info",
  templateUrl: "./client-info.page.html",
  styleUrls: ["./client-info.page.css"],
})
export class ClientInfoPage implements OnInit {
  public clientInfoForm: FormGroup = new FormGroup({
    client_name: new FormControl(),
    nation_id: new FormControl(),
    gender: new FormControl(),
    birth_date: new FormControl(),
    marital_status: new FormControl(),
    client_type: new FormControl(),
    id_date: new FormControl(),
    edu_level: new FormControl(),
    gov: new FormControl(),
    vill: new FormControl(),
    dist: new FormControl(),
    home_address: new FormControl(),
    mobile_1: new FormControl(),
    mobile_2: new FormControl(),
    email: new FormControl(),
  });

  constructor(
    private formBuilder: FormBuilder,
    private http: HttpClient,
    private env: EnvService,
    private authService: MohassilAuthService,
    private datepipe: DatePipe
  ) {}

  //userInfo
  org_code_user_info: string;
  branch_code_user_info: string;

  //variables
  client_name: string;
  nation_id: string;
  gender: string;
  birth_date: string;
  marital_status: string;
  client_type: string;
  id_date: string;
  edu_level: string;
  gov: string;
  vill: string;
  dist: string;
  home_address: string;
  mobile_1: string;
  mobile_2: string;
  email: string;
  //notFound: string = "لا يوجد";

  client_info: any[] = [
    {
      client_key: "190020021947",
      client_name: "Bishoy",
      birth_date: "1991-08-09 12:00:00 AM",
      nation_id: "29108090202812",
      id_date: "2021-03-01 12:00:00 AM",
      marital_status: "اعزب",
      client_type: "فردى",
      edu_level: "بكالوريوس",
      gov: "القاهرة",
      dist: "قسم الساحل",
      vill: "الساحل",
      gender: "ذكر",
      mobile_1: "01284000076",
      mobile_2: null,
      home_Add_1: "14ب شارع مصنع السماد",
      email_1: "bishoysamy@pm.me",
    },
  ];

  async ngOnInit() {
    await this.authService.getUserInfo().then((userInfo) => {
      this.branch_code_user_info = userInfo.branch_code;
      this.org_code_user_info = userInfo.org_code;
    });
    await this.getData();
    this.clientInfoForm.setValue({
      client_name: new FormControl(this.client_name).value,
      nation_id: new FormControl(this.nation_id).value,
      gender: new FormControl(this.gender).value,
      birth_date: new FormControl(this.birth_date).value,
      marital_status: new FormControl(this.marital_status).value,
      client_type: new FormControl(this.client_type).value,
      id_date: new FormControl(this.id_date).value,
      edu_level: new FormControl(this.edu_level).value,
      gov: new FormControl(this.gov).value,
      vill: new FormControl(this.vill).value,
      dist: new FormControl(this.dist).value,
      home_address: new FormControl(this.home_address).value,
      mobile_1: new FormControl(this.mobile_1).value,
      mobile_2: new FormControl(this.mobile_2).value,
      email: new FormControl(this.email).value,
    });
  }

  async getData() {
    this.client_name = this.client_info[0].client_name;
    this.client_type = this.client_info[0].client_type;
    var birthString = this.client_info[0].birth_date;
    var subbirthString = birthString.split(" ");
    this.birth_date = subbirthString[0];
    this.nation_id = this.client_info[0].nation_id;
    this.gender = this.client_info[0].gender;
    this.marital_status = this.client_info[0].marital_status;
    var idDateString = this.client_info[0].id_date;
    var subidDateString = idDateString.split(" ");
    this.id_date = subidDateString[0];
    this.edu_level = this.client_info[0].edu_level;
    this.gov = this.client_info[0].gov;
    this.dist = this.client_info[0].dist;
    this.vill = this.client_info[0].vill;
    this.home_address = this.client_info[0].home_Add_1;
    this.mobile_1 = this.client_info[0].mobile_1;
    this.mobile_2 = this.client_info[0].mobile_2;
    this.email = this.client_info[0].email_1;
  }
}
